import React from 'react'
import Feature from './Feature'
import { useNavigate } from 'react-router-dom'

const Home = () => {
  const navigate=useNavigate();

  function clickHandler(event)
  {
    navigate("/services");
  }
  return (
    <div className='flex flex-col justify-between items-center w-11/12 max-w-[1160px] py-4 mx-auto' >
        <div className='flex'>
          <div className='max-w-[310px]'>
            <h1>INDIA'S TRUSTED HOME MAKERS</h1>
            <p>HouseMaker is the simplest way to get your life in order with the right domestic help</p>
            <button onClick={clickHandler}
            className='text-white'> Book Now</button>
          </div>
          <div className='grid grid-cols-2'>
            
          </div>
        </div>
        <Feature/>
    </div>
  )
}

export default Home
